import{_ as i,o as e,c as n,a2 as t}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"Pretraining、SFT、偏好优化、Prompt、RAG 与 Fine-tuning","description":"","frontmatter":{"type":"ai-note","stage":"beginner","topic":"model-adaptation-methods","verified":"2026-07-17T00:00:00.000Z","tags":["ai","pretraining","sft","preference-optimization","prompt","rag","fine-tuning"]},"headers":[],"relativePath":"04-ai/notes/00-foundations/model-adaptation-methods.md","filePath":"04-ai/notes/00-foundations/model-adaptation-methods.md","lastUpdated":1784542968000}'),l={name:"04-ai/notes/00-foundations/model-adaptation-methods.md"};function s(r,a,o,p,d,h){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="pretraining、sft、偏好优化、prompt、rag-与-fine-tuning" tabindex="-1">Pretraining、SFT、偏好优化、Prompt、RAG 与 Fine-tuning <a class="header-anchor" href="#pretraining、sft、偏好优化、prompt、rag-与-fine-tuning" aria-label="Permalink to &quot;Pretraining、SFT、偏好优化、Prompt、RAG 与 Fine-tuning&quot;">​</a></h1><h2 id="_1-概念、用途与工程边界" tabindex="-1">1. 概念、用途与工程边界 <a class="header-anchor" href="#_1-概念、用途与工程边界" aria-label="Permalink to &quot;1. 概念、用途与工程边界&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><ul><li>Pretraining：在大规模数据上训练基础模型，学习通用表示和生成能力。</li><li>SFT（Supervised Fine-Tuning）：使用输入与目标输出样例继续训练，塑造任务行为和格式。</li><li>偏好优化：使用人类或模型偏好数据，让模型更倾向被选中的响应；具体算法包括 RLHF、DPO 等，不能互相等同。</li><li>Prompt：在推理时提供任务、上下文、约束和示例，不更新模型参数。</li><li>RAG：推理前从外部知识源检索内容并加入上下文，使回答可使用最新、私有或可引用资料。</li><li>Fine-tuning：所有继续更新模型参数的训练方法的宽泛称呼，SFT 和偏好优化都可属于其中。</li></ul><h3 id="为什么需要区分" tabindex="-1">为什么需要区分 <a class="header-anchor" href="#为什么需要区分" aria-label="Permalink to &quot;为什么需要区分&quot;">​</a></h3><p>每种方法解决的问题、数据需求、费用、更新速度和风险不同。把所有质量问题都交给 Fine-tuning 会增加数据和运维成本，也不能自动解决最新知识、权限或引用。</p><h3 id="核心选择规则" tabindex="-1">核心选择规则 <a class="header-anchor" href="#核心选择规则" aria-label="Permalink to &quot;核心选择规则&quot;">​</a></h3><ol><li>任务和成功标准不清：先定义评估集，不先改模型。</li><li>指令、格式或少量示例即可表达：先改 Prompt 和 Schema。</li><li>规则确定且必须保证：使用代码校验或确定性逻辑。</li><li>需要最新、私有、可删除和可引用知识：优先 RAG 或 Tool。</li><li>需要执行外部动作或精确事实：使用 Tool，并在服务端校验权限。</li><li>大量稳定样例显示特定行为、风格或任务模式无法靠前述方法达到：评估 Fine-tuning。</li><li>人类偏好难以写成单一参考答案：在高质量偏好数据和可靠评测下考虑偏好优化。</li></ol><h3 id="工程使用" tabindex="-1">工程使用 <a class="header-anchor" href="#工程使用" aria-label="Permalink to &quot;工程使用&quot;">​</a></h3><p>建立基线顺序：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础模型 + 简单 Prompt</span></span>
<span class="line"><span>→ 明确 Prompt + Structured Output</span></span>
<span class="line"><span>→ 代码规则 / Tool</span></span>
<span class="line"><span>→ RAG + 引用</span></span>
<span class="line"><span>→ 更合适的模型</span></span>
<span class="line"><span>→ SFT / 偏好优化</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>每一步在同一评估集上比较质量、延迟、成本和安全。Fine-tuning 前确认数据许可、隐私、划分、版本、回滚和模型生命周期。</p><h3 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h3><ul><li>用 Fine-tuning 注入会频繁变化的事实；更新和删除困难。</li><li>认为 RAG 能保证正确；检索可能漏召回、召回过时或不相关内容，生成仍可能不受证据约束。</li><li>用 Prompt 要求模型执行确定性权限规则。</li><li>把供应商“微调”统一理解为同一种算法，不看训练目标和支持能力。</li><li>没有独立评估集就训练，无法判断改善还是记忆训练样例。</li></ul><h3 id="延伸机制" tabindex="-1">延伸机制 <a class="header-anchor" href="#延伸机制" aria-label="Permalink to &quot;延伸机制&quot;">​</a></h3><p>方法可以组合，例如经过 SFT 的模型使用 RAG 和 Tool。但组合会增加故障点，应能定位问题发生在任务定义、模型、检索、上下文、工具还是验证阶段。</p><h2 id="方法作用层级" tabindex="-1">方法作用层级 <a class="header-anchor" href="#方法作用层级" aria-label="Permalink to &quot;方法作用层级&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;任务与评测&quot;] --&gt; B[&quot;Prompt：改变推理输入&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; C[&quot;RAG/Tool：提供外部事实或动作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; D[&quot;SFT：用目标输出更新参数&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; E[&quot;偏好优化：用比较信号更新行为&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F[&quot;Pretraining：学习基础表示与生成能力&quot;] --&gt; B</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; D</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这些方法作用于不同层。RAG 更新知识源不更新模型参数；SFT 可以改变输出模式，但不提供可即时删除的事实库；偏好优化依赖偏好定义，不能代替权限校验。</p><h2 id="输入、产出与边界" tabindex="-1">输入、产出与边界 <a class="header-anchor" href="#输入、产出与边界" aria-label="Permalink to &quot;输入、产出与边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方法</th><th>主要输入</th><th>主要产出</th><th>不直接解决</th></tr></thead><tbody><tr><td>Prompt</td><td>指令、上下文、示例</td><td>单次推理行为</td><td>权限和确定性不变量</td></tr><tr><td>RAG</td><td>文档、索引、查询</td><td>检索上下文与引用候选</td><td>生成事实保证</td></tr><tr><td>Tool</td><td>Schema、授权身份、外部系统</td><td>查询结果或副作用</td><td>模型参数学习</td></tr><tr><td>SFT</td><td>输入—目标输出样例</td><td>新模型版本/Adapter</td><td>高频变化知识的即时更新</td></tr><tr><td>偏好优化</td><td>响应对与偏好信号</td><td>更符合偏好目标的版本</td><td>偏好数据本身的偏差</td></tr></tbody></table><h2 id="完整选择示例" tabindex="-1">完整选择示例 <a class="header-anchor" href="#完整选择示例" aria-label="Permalink to &quot;完整选择示例&quot;">​</a></h2><p>客服系统需要回答最新退款政策并执行退款。政策文档进入带版本和权限的检索库；订单状态由 Tool 实时查询；退款窗口、金额和权限由服务端代码校验；Prompt 规定回答任务与失败行为。只有当大量稳定样例显示表达或分类行为仍系统性不足，且独立测试集可验证收益时，才评估 SFT。任何模型版本都不能绕过服务端退款规则。</p><h2 id="验证与排错" tabindex="-1">验证与排错 <a class="header-anchor" href="#验证与排错" aria-label="Permalink to &quot;验证与排错&quot;">​</a></h2><p>按“任务定义 → 上下文/检索 → Tool → 模型 → Schema → 业务规则”记录失败层。每增加一种适配方法，都与前一基线在同一数据版本上比较质量、延迟、成本、隐私和回滚复杂度。</p><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为“内部制度问答并提交请假”设计方案。验收：分别标出 Prompt、RAG、Tool 和代码职责；说明是否需要微调及证据；包含权限、无答案、文档过期、Tool 失败和回滚路径。</p><h2 id="完整案例-制度问答的适配决策" tabindex="-1">完整案例：制度问答的适配决策 <a class="header-anchor" href="#完整案例-制度问答的适配决策" aria-label="Permalink to &quot;完整案例：制度问答的适配决策&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>目标：仅依据公司当前制度回答员工问题，并给出文档与段落引用。</li><li>数据：制度每周可能更新，部分文档按部门授权。</li><li>基线结果：格式通过率 92%，事实支持率 71%，主要失败是漏检最新文档和引用不匹配。</li><li>不变量：模型不能扩大用户文档权限，不能自行批准申请。</li></ul><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>先冻结包含正常、无答案、冲突版本和无权限文档的评测集。</li><li>用 Structured Output 修复字段缺失，运行时校验引用数组和状态枚举。</li><li>建立按文档版本与权限过滤的 RAG；检索结果保存原文位置和发布日期。</li><li>服务端代码检查用户身份与文档 ACL，模型只看到授权片段。</li><li>用 Tool 查询申请状态，但批准动作由确定性工作流和授权人执行。</li><li>比较基线与 RAG 版本。若稳定的语言风格或分类仍不达标，再收集 SFT 数据；不以微调存储每周变化制度。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>方案：Prompt + Structured Output + RAG + 只读 Tool + 服务端授权</span></span>
<span class="line"><span>暂不采用：SFT、偏好优化</span></span>
<span class="line"><span>理由：主要失败来自知识新鲜度、引用和权限，不是稳定行为模式</span></span>
<span class="line"><span>发布门槛：支持率≥95%，越权召回=0，无答案准确率≥98%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>删除或更新制度后重新索引，旧段落不再被召回。</li><li>用同一评测集分别测检索 Recall@K、引用对齐和最终回答。</li><li>人为放入“忽略规则”的恶意文档，服务端权限和工具白名单不改变。</li><li>记录各层耗时与失败类别，确认收益不是由隐藏更强模型造成。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若检索已返回正确段落但回答仍无支持结论，问题位于生成约束、上下文排序或模型能力；若正确段落根本未召回，继续修改 Prompt 不能修复检索。失败必须按层定位后再选择方法。</p><h2 id="边界检查矩阵" tabindex="-1">边界检查矩阵 <a class="header-anchor" href="#边界检查矩阵" aria-label="Permalink to &quot;边界检查矩阵&quot;">​</a></h2><ol><li>任务不清：先定义输入、输出与评测，不选择训练方法。</li><li>格式不稳：优先 Structured Output 与运行时校验。</li><li>确定规则：计算、权限和状态转换由代码执行。</li><li>知识变化：优先可更新、可引用、可删除的 RAG 或 Tool。</li><li>实时事实：通过受控 Tool 查询，不写入参数。</li><li>行为模式：稳定且大量样例支持时才评估 SFT。</li><li>主观偏好：明确偏好数据来源和冲突，再考虑偏好优化。</li><li>数据许可：训练和检索都要检查使用、保留与删除权限。</li><li>组合故障：分别测检索、生成、工具与最终状态。</li><li>成本：训练费用外还包括数据、评测、部署和版本迁移。</li><li>回滚：保留基线模型、索引和 Prompt 的可恢复版本。</li><li>供应商：同名 Fine-tuning 能力不保证训练目标相同。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2203.02155" target="_blank" rel="noreferrer">Ouyang et al.：Training language models to follow instructions with human feedback</a>（访问日期：2026-07-17）</li><li><a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Lewis et al.：Retrieval-Augmented Generation</a>（访问日期：2026-07-17）</li><li><a href="https://arxiv.org/abs/2305.18290" target="_blank" rel="noreferrer">Rafailov et al.：Direct Preference Optimization</a>（访问日期：2026-07-17）</li><li><a href="https://huggingface.co/learn/llm-course/" target="_blank" rel="noreferrer">Hugging Face LLM Course</a>（访问日期：2026-07-17）</li></ul>`,42)])])}const b=i(l,[["render",s]]);export{c as __pageData,b as default};
